module RefModule(clk, rst, start, data_in, sorted_out, done);  
    input clk;  
    input rst;  
    input start;  
    input [31:0] data_in;  
    output reg [31:0] sorted_out;  
    output reg done;  

    reg [3:0] unused_array [0:7];  
    reg [3:0] temp [0:7];  
    reg [2:0] stage;  
    integer i, j, k;  

    always @(posedge clk or posedge rst) begin  
        if (rst) begin  
            sorted_out <= 32'b0;  
            done <= 1'b0;  
            stage <= 3'b000;  
        end  
        else if (start) begin  
            for (i = 0; i < 8; i = i + 1)  
                unused_array[i] = data_in[(i*4)+:4];  
            stage <= 3'b001;  
        end  
        else if (stage == 3'b001) begin  
            // Merge sort process  
            // Pseudo-code implementation for merge sort  
            for (i = 0; i < 7; i = i + 1) begin  
                for (j = 0; j < 7 - i; j = j + 1) begin  
                    if (unused_array[j] > unused_array[j + 1]) begin  
                        temp[j] = unused_array[j];  
                        unused_array[j] = unused_array[j + 1];  
                        unused_array[j + 1] = temp[j];  
                    end  
                end  
            end  
            stage <= 3'b010;  
        end  
        else if (stage == 3'b010) begin  
            // Prepare sorted output  
            sorted_out <= {unused_array[0], unused_array[1], unused_array[2], unused_array[3], unused_array[4], unused_array[5], unused_array[6], unused_array[7]};  
            done <= 1'b1;  
            stage <= 3'b000;  
        end  
    end  
endmodule
